1	import { UserRole, type AssetModel, type AssetInstance } from "@prisma/client";
2	
3	type Role = "EMPLOYEE" | "MANAGER" | "IT_ADMIN" | "EXECUTIVE";
4	
5	type AssetInstanceWithModel = AssetInstance & { model?: AssetModel | null };
6	
7	export function sanitizeAssetModel(
8	  model: AssetModel,
9	  role: Role,
10	): Record<string, unknown> {
11	  const base = model as unknown as Record<string, unknown>;
12	
13	  if (role === "EMPLOYEE" || role === "MANAGER") {
14	    const { purchasePrice, supplier, sn, ...rest } = base;
15	    return rest;
16	  }
17	
18	  if (role === "EXECUTIVE") {
19	    const { supplier, sn, ...rest } = base;
20	    return rest;
21	  }
22	
23	  // IT_ADMIN: full visibility
24	  return base;
25	}
26	
27	export function sanitizeAssetInstance(
28	  instance: AssetInstanceWithModel,
29	  role: Role,
30	): Record<string, unknown> {
31	  const base = { ...instance } as unknown as Record<string, unknown>;
32	
33	  if (instance.model) {
34	    base.model = sanitizeAssetModel(instance.model, role) as Record<
35	      string,
36	      unknown
37	    >;
38	  }
39	
40	  if (role === "EMPLOYEE" || role === "MANAGER") {
41	    const { purchasePrice, supplier, sn, ...rest } = base;
42	    return rest;
43	  }
44	
45	  if (role === "EXECUTIVE") {
46	    const { supplier, sn, ...rest } = base;
47	    return rest;
48	  }
49	
50	  return base;
51	}
