1	import { AssetInstanceStatus } from "@prisma/client";
2	import type { Prisma } from "@prisma/client";
3	
4	const allowedTransitionsMap: Record<AssetInstanceStatus, AssetInstanceStatus[]> = {
5	  IN_STOCK: ["AVAILABLE"],
6	  AVAILABLE: ["ASSIGNED", "LOST"],
7	  ASSIGNED: ["IN_USE", "AVAILABLE", "LOST"],
8	  IN_USE: ["RETURNING", "REPAIRING", "TRANSFERRING", "LOST"],
9	  RETURNING: ["AVAILABLE", "SCRAPPED"],
10	  REPAIRING: ["IN_USE", "AVAILABLE", "SCRAPPED"],
11	  TRANSFERRING: ["IN_USE"],
12	  LOST: [],
13	  SCRAPPED: [],
14	};
15	
16	export class TransitionError extends Error {
17	  constructor(message: string) {
18	    super(message);
19	    this.name = "TransitionError";
20	  }
21	}
22	
23	export class AssetStateMachine {
24	  static allowedTransitions = new Map(
25	    Object.entries(allowedTransitionsMap),
26	  ) as Map<AssetInstanceStatus, AssetInstanceStatus[]>;
27	
28	  static canTransition(
29	    from: AssetInstanceStatus,
30	    to: AssetInstanceStatus,
31	  ): boolean {
32	    const allowed = allowedTransitionsMap[from];
33	    return allowed?.includes(to) ?? false;
34	  }
35	
36	  static async transition(
37	    tx: Prisma.TransactionClient,
38	    assetId: string,
39	    to: AssetInstanceStatus,
40	    context: {
41	      operatorId: string;
42	      lostReason?: string;
43	      scrapReason?: string;
44	    },
45	  ): Promise<{
46	    asset: Record<string, unknown>;
47	    before: Record<string, unknown>;
48	    after: Record<string, unknown>;
49	    cancelledTicketIds: string[];
50	  }> {
51	    const asset = await tx.assetInstance.findUnique({
52	      where: { id: assetId },
53	    });
54	
55	    if (!asset) {
56	      throw new TransitionError("Asset not found");
57	    }
58	
59	    const from = asset.status;
60	
61	    if (!AssetStateMachine.canTransition(from, to)) {
62	      throw new TransitionError(
63	        `Cannot transition asset from ${from} to ${to}`,
64	      );
65	    }
66	
67	    const before = { ...asset };
68	    let cancelledTicketIds: string[] = [];
69	
70	    if (to === "LOST") {
71	      const activeTickets = await tx.ticket.findMany({
72	        where: {
73	          targetAssetId: assetId,
74	          status: { notIn: ["COMPLETED", "CANCELLED", "REJECTED"] },
75	        },
76	      });
77	      cancelledTicketIds = activeTickets.map((t) => t.id);
78	      if (cancelledTicketIds.length > 0) {
79	        await tx.ticket.updateMany({
80	          where: { id: { in: cancelledTicketIds } },
81	          data: { status: "CANCELLED" },
82	        });
83	      }
84	    }
85	
86	    const updateData: Record<string, unknown> = { status: to };
87	
88	    if (to === "LOST" && context.lostReason) {
89	      updateData.lostReason = context.lostReason;
90	    }
91	    if (to === "SCRAPPED") {
92	      if (context.scrapReason) {
93	        updateData.scrapReason = context.scrapReason;
94	      }
95	      updateData.holderId = null;
96	    }
97	    if (to === "AVAILABLE") {
98	      updateData.holderId = null;
99	    }
100	
101	    const updated = await tx.assetInstance.update({
102	      where: { id: assetId },
103	      data: updateData as Prisma.AssetInstanceUpdateInput,
104	    });
105	
106	    return {
107	      asset: updated as unknown as Record<string, unknown>,
108	      before,
109	      after: updated as unknown as Record<string, unknown>,
110	      cancelledTicketIds,
111	    };
112	  }
113	}
