}

import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

export type AssetInstanceStatus =
  | "IN_STOCK"
  | "AVAILABLE"
  | "ASSIGNED"
  | "IN_USE"
  | "RETURNING"
  | "REPAIRING"
  | "TRANSFERRING"
  | "LOST"
  | "SCRAPPED";

const statusConfig: Record<
  AssetInstanceStatus,
  { label: string; variant: "default" | "secondary" | "outline" | "destructive" | "ghost" | "link"; className?: string }
> = {
  IN_STOCK: { label: "在库", variant: "ghost", className: "text-muted-foreground" },
  AVAILABLE: { label: "可用", variant: "default", className: "bg-green-500/10 text-green-600 hover:bg-green-500/20 dark:text-green-400" },
  ASSIGNED: { label: "已分配", variant: "default", className: "bg-blue-500/10 text-blue-600 hover:bg-blue-500/20 dark:text-blue-400" },
  IN_USE: { label: "使用中", variant: "default", className: "bg-teal-500/10 text-teal-600 hover:bg-teal-500/20 dark:text-teal-400" },
  RETURNING: { label: "归还中", variant: "outline", className: "border-yellow-400 text-yellow-600 dark:text-yellow-400" },
  REPAIRING: { label: "维修中", variant: "outline", className: "border-orange-400 text-orange-600 dark:text-orange-400" },
  TRANSFERRING: { label: "调拨中", variant: "outline", className: "border-purple-400 text-purple-600 dark:text-purple-400" },
  LOST: { label: "丢失", variant: "destructive" },
  SCRAPPED: { label: "已报废", variant: "ghost", className: "text-muted-foreground" },
};

interface AssetStatusBadgeProps {
  status: AssetInstanceStatus;
  className?: string;
}

export function AssetStatusBadge({ status, className }: AssetStatusBadgeProps) {
  const config = statusConfig[status] ?? {
    label: status,
    variant: "outline" as const,
  };

  return (
    <Badge
      variant={config.variant}
      className={cn(config.className, className)}
    >
      {config.label}
    </Badge>
  );
}

import Link from "next/link";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Inbox, type LucideIcon } from "lucide-react";

interface EmptyStateAction {
  label: string;
  href?: string;
  onClick?: () => void;
}

interface EmptyStateProps {
  icon?: LucideIcon;
  title: string;
  description?: string;
  action?: EmptyStateAction;
  className?: string;
}

export function EmptyState({
  icon: Icon = Inbox,
  title,
  description,
  action,
  className,
}: EmptyStateProps) {
  const content = (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-3 py-12 text-center",
        className,
      )}
    >
      <div className="flex size-12 items-center justify-center rounded-full bg-muted">
        <Icon className="size-6 text-muted-foreground" />
      </div>
      <div>
        <h3 className="text-sm font-medium text-foreground">{title}</h3>
        {description && (
          <p className="mt-1 text-sm text-muted-foreground">{description}</p>
        )}
      </div>
      {action && (
        <>
          {action.href ? (
            <Link href={action.href}>
              <Button variant="outline" size="sm">
                {action.label}
              </Button>
            </Link>
          ) : (
            <Button variant="outline" size="sm" onClick={action.onClick}>
              {action.label}
            </Button>
          )}
        </>
      )}
    </div>
  );

  return content;
}

"use client";

import Link from "next/link";
import { Bell } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useAuth } from "@/lib/auth-context";

export function NotificationBell() {
  const { unreadNotifications } = useAuth();

  return (
    <Link href="/notifications">
      <Button
        variant="ghost"
        size="icon-sm"
        className="relative"
        aria-label={`通知${unreadNotifications > 0 ? ` (${unreadNotifications}条未读)` : ""}`}
      >
        <Bell className="size-4" />
        {unreadNotifications > 0 && (
          <Badge className="absolute -top-1 -right-1 flex size-4 min-w-0 items-center justify-center rounded-full p-0 text-[10px] leading-none">
            {unreadNotifications > 99 ? "99+" : unreadNotifications}
          </Badge>
        )}
      </Button>
    </Link>
  );
}

"use client";

import { useAuth, type UserRole } from "@/lib/auth-context";

interface RoleGuardProps {
  roles: UserRole[];
  children: React.ReactNode;
  fallback?: React.ReactNode;
}

export function RoleGuard({
  roles,
  children,
  fallback = null,
}: RoleGuardProps) {
  const { user } = useAuth();

  if (!roles.includes(user.role)) {
    return <>{fallback}</>;
  }

  return <>{children}</>;
}

import { cn } from "@/lib/utils";

interface TimelineEvent {
  label: string;
  time: string;
  description?: string;
}

interface TicketTimelineProps {
  events: TimelineEvent[];
  className?: string;
}

export function TicketTimeline({ events, className }: TicketTimelineProps) {
  if (events.length === 0) return null;

  return (
    <div className={cn("relative", className)}>
      {events.map((event, index) => {
        const isLast = index === events.length - 1;

        return (
          <div key={index} className="relative flex gap-3 pb-6 last:pb-0">
            {/* Timeline line + indicator */}
            <div className="flex flex-col items-center">
              <div
                className={cn(
                  "z-10 flex size-3 shrink-0 items-center justify-center rounded-full border-2",
                  "border-primary bg-background",
                )}
              />
              {!isLast && (
                <div className="mt-0.5 w-px flex-1 bg-border" />
              )}
            </div>

            {/* Event content */}
            <div className="min-w-0 flex-1 -mt-0.5">
              <div className="flex items-baseline justify-between gap-2">
                <span className="text-sm font-medium text-foreground">
                  {event.label}
                </span>
                <span className="shrink-0 text-xs text-muted-foreground">
                  {event.time}
                </span>
              </div>
              {event.description && (
                <p className="mt-0.5 text-sm text-muted-foreground">
                  {event.description}
                </p>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

